const webhookData = $('Webhook – Lead Intake (Visualizer)').first().json.body;
const configData = $('Config – GHL IDs').first().json;
const contact = webhookData.contact || {};
const fields = webhookData.fields || {};
const utm = webhookData.utm || {};

const FIELD_IDS = {
  lead_source: 'pOqyjdxOHg67C4JWdkaG',
  current_roof_type: 'Vo7YnqmuZnhV2U66uKJA',
  project_reason: 'prLMUoMzKClcfmBzDH3R',
  insurance_claim_status: 'tpAq0AZMqWJZeTy3dPsS',
  homeowner_timeline: '7F3CKSSVRj7jdHKoq87X',
  property_address: 'acFCeylcy8uhep3stymL',
  selected_roof_type: 'ooxcklKOKGrDCRunZnh3',
  estimated_roof_size: 'S3E1cQMFQ2vD2Ec1nSAR',
  estimate_range: 'cEjn1x0nid6taqIaQxKt',
  solar_failure_reason: 'BGNa09wcBsV8K1wJaWpz',
  roof_size_source: 'DM5heXbAUYr0bzz7qmpZ',
};
const UTM_FIELD_IDS = {
  source: 'NNZiielScQomx8VDF7q8',
  medium: 'ELW45zGCkwQkpUV2TnEW',
  campaign: 'VrI3HZtaymdTdf0lggfD',
};

const isEmpty = (v) => v === null || v === undefined || v === '';

// Base contact fields — never-null-write: only include keys that are actually present
const contactFields = {};
for (const key of ['firstName', 'lastName', 'email', 'phone', 'address1', 'city', 'state', 'postalCode']) {
  if (!isEmpty(contact[key])) contactFields[key] = contact[key];
}

const customFields = [];
for (const [key, id] of Object.entries(FIELD_IDS)) {
  if (!isEmpty(fields[key])) customFields.push({ id, value: fields[key] });
}
for (const [key, id] of Object.entries(UTM_FIELD_IDS)) {
  if (!isEmpty(utm[key])) customFields.push({ id, value: utm[key] });
}
if (customFields.length) contactFields.customFields = customFields;
const baseTags = Array.isArray(webhookData.tags) ? webhookData.tags : [];
const allTags = webhookData.smsConsent === true ? [...baseTags, 'SMS Consent'] : baseTags;

// Tags are set on contactPayloadCreate (brand-new contact, nothing to clobber) but
// deliberately left OFF contactPayloadUpdate — GHL's PUT /contacts/{id} replaces the
// entire tags array, so including it here would silently wipe any tags the contact
// already had (e.g. 'sms inquiry', manual CRM tags). Existing contacts get any new
// tags added additively via the dedicated Add Tags endpoint instead (see updateTags).
const contactPayloadCreate = { ...contactFields, locationId: configData.locationId };
if (allTags.length) contactPayloadCreate.tags = allTags;
const contactPayloadUpdate = { ...contactFields };
const updateTags = allTags;

return [{
  json: {
    email: contact.email,
    contactPayloadCreate,
    contactPayloadUpdate,
    updateTags,
    rawFields: fields,
    locationId: configData.locationId,
    pipelineId: configData.pipelineId,
    stageId: configData.stageId,
    firstName: contact.firstName || '',
    lastName: contact.lastName || '',
    phone: contact.phone || '',
    source: webhookData.source || 'visualizer',
  },
}];

const webhookData = $('Webhook – Lead Intake (Visualizer)').first().json.body;
const configData = $('Config – GHL IDs').first().json;
const contact = webhookData.contact || {};
const fields = webhookData.fields || {};
const utm = webhookData.utm || {};

const FIELD_IDS = {
  property_address: 'acFCeylcy8uhep3stymL',
  selected_roof_type: 'ooxcklKOKGrDCRunZnh3',
};
const UTM_FIELD_IDS = {
  source: 'NNZiielScQomx8VDF7q8',
  medium: 'ELW45zGCkwQkpUV2TnEW',
  campaign: 'VrI3HZtaymdTdf0lggfD',
};

const isEmpty = (v) => v === null || v === undefined || v === '';

const contactFields = {};
for (const key of ['firstName', 'address1', 'city', 'state', 'postalCode']) {
  if (!isEmpty(contact[key])) contactFields[key] = contact[key];
}

const customFields = [];
for (const [key, id] of Object.entries(FIELD_IDS)) {
  if (!isEmpty(fields[key])) customFields.push({ id, value: fields[key] });
}
for (const [key, id] of Object.entries(UTM_FIELD_IDS)) {
  if (!isEmpty(utm[key])) customFields.push({ id, value: utm[key] });
}
if (customFields.length) contactFields.customFields = customFields;

const contactPayload = { ...contactFields, locationId: configData.locationId, tags: ['Visualizer Partial'] };

return [{ json: { contactPayload, locationId: configData.locationId } }];

const search = $("Search Opportunities For Contact").first().json;
const cfg = $("Config – GHL IDs").first().json;
const built = $("Build Contact Payload (Filter Nulls)").first().json;
const normalized = $("Normalize Contact Result").first().json;
const opportunities = Array.isArray(search.opportunities) ? search.opportunities : [];
// Defense in depth: never trust a result that doesn't actually belong to this
// contact — a missing/blank contactId upstream should fail safe (create new),
// not silently adopt whatever opportunity the search happens to return.
const existing = opportunities.find(o => o.contactId === normalized.contactId) || null;
let opportunityAction = 'create';
let opportunityId = null;
if (existing && existing.id) {
  opportunityId = existing.id;
  opportunityAction = (existing.pipelineStageId === cfg.stageId) ? 'updateStage' : 'noop';
}
return [{ json: { contactId: normalized.contactId, firstName: built.firstName,
  lastName: built.lastName, phone: built.phone, source: built.source,
  locationId: built.locationId, pipelineId: built.pipelineId, stageId: built.stageId,
  opportunityAction, opportunityId } }];

// Converge the three dedup branches (create / updateStage / noop) into one
// consistent shape so downstream nodes (Add Insurance Claim Tag, Execute
// Workflow – New Lead Alert SMS) always see both a flat contactId and a
// nested opportunity.contactId, regardless of which branch fired.
const input = $json;
const contactId = input.opportunity ? input.opportunity.contactId : input.contactId;
return [{ json: { ...input, contactId, opportunity: input.opportunity || { contactId } } }];
